						const timestamp = instance.get('timestamp');

						// LPS-82336 Maintain session state in multiple tabs

						if (instance._initTimestamp !== timestamp) {
							instance.set('timestamp', timestamp);

							if (sessionState !== 'active') {
								instance.set(
									'sessionState',
									'active',
									SRC_EVENT_OBJ
								);
							}
						}

