					instance._stopTimer();
				},

				expire() {
					const instance = this;

					instance.set('sessionState', 'expired', SRC_EVENT_OBJ);
				},

				extend() {
					const instance = this;

					instance.set('sessionState', 'active', SRC_EVENT_OBJ);
				},

