						'LFR_SESSION_STATE_' + themeDisplay.getRealUserId();

					instance._cookieOptions = {
						path: themeDisplay.getPathContext() || '/',
						secure: A.UA.secure,
					};

					instance._registered = {};

					instance.set('timestamp');

					instance._initEvents();

					instance._startTimer();

