							element.fieldName === fieldName &&
							element.validatorName === validatorName
						) {
							ruleIndex = index;

							return true;
						}
					});

					return ruleIndex;
				},

				_focusInvalidFieldTab() {
					const instance = this;

					const formNode = instance.formNode;

					const field = formNode.one(
						'.' + instance.formValidator.get('errorClass')
