  "definition" : "{\"availableLanguageIds\":[\"en_GB\"],\"successPage\":{\"body\":{\"en_GB\":\"Your information was successfully received, and your reference number is $FORM_REFERENCE$.\"},\"title\":{\"en_GB\":\"Thank you.\"},\"enabled\":true},\"defaultLanguageId\":\"en_GB\",\"rules\":[{\"condition\":\"not(isEmpty(getValue('Text06802196')))\",\"name\":{\"en_GB\":\"[{\\\"unicodeLocaleKeys\\\":[],\\\"ISO3Language\\\":\\\"eng\\\",\\\"country\\\":\\\"GB\\\",\\\"displayName\\\":\\\"English (United Kingdom)\\\",\\\"displayVariant\\\":\\\"\\\",\\\"language\\\":\\\"en\\\",\\\"displayLanguage\\\":\\\"English\\\",\\\"script\\\":\\\"\\\",\\\"unicodeLocaleAttributes\\\":[],\\\"displayCountry\\\":\\\"United Kingdom\\\",\\\"ISO3Country\\\":\\\"GBR\\\",\\\"variant\\\":\\\"\\\",\\\"extensionKeys\\\":[],\\\"displayScript\\\":\\\"\\\"}]\"},\"actions\":[\"call('9c4d47ca-1e8c-0217-2b3e-b8dcfa2663fc', 'uprn=Text06802196', 'CheckboxMultiple75509060=IZSJ0coK')\"],\"enabled\":true},{\"condition\":\"not(isEmpty(getValue('Address94394335'))) AND contains(getValue('Text06802196'), 'ABC')\",\"name\":{\"en_GB\":\"[{\\\"unicodeLocaleKeys\\\":[],\\\"ISO3Language\\\":\\\"eng\\\",\\\"country\\\":\\\"GB\\\",\\\"displayName\\\":\\\"English (United Kingdom)\\\",\\\"displayVariant\\\":\\\"\\\",\\\"language\\\":\\\"en\\\",\\\"displayLanguage\\\":\\\"English\\\",\\\"script\\\":\\\"\\\",\\\"unicodeLocaleAttributes\\\":[],\\\"displayCountry\\\":\\\"United Kingdom\\\",\\\"ISO3Country\\\":\\\"GBR\\\",\\\"variant\\\":\\\"\\\",\\\"extensionKeys\\\":[],\\\"displayScript\\\":\\\"\\\"}]\"},\"actions\":[\"setVisible('CheckboxMultiple75509060', true)\"],\"enabled\":true}],\"fields\":[{\"rulesConditionDisabled\":true,\"dataType\":\"\",\"predefinedValue\":{\"en_GB\":\"\"},\"readOnly\":false,\"label\":{\"en_GB\":\"Check your bin collection days\"},\"type\":\"paragraph\",\"showLabel\":true,\"required\":false,\"fieldNamespace\":\"\",\"visibilityExpression\":\"\",\"indexType\":\"keyword\",\"repeatable\":false,\"name\":\"