 let lastField = document.querySelector("[name*='Javascript25292660']"); 
 if(lastField) { 
 clearInterval(javaScriptIntervalIdJavascript25292660); 
// Variables
let postcode;
let button;
let multiSelect = [];
let multiSelectValues = [];
let apiReturnArray = [];
let formattedArray = [];
const observerConfig = {
    childList: true, // Observe direct children
    subtree: true, // Observe all descendants
    characterData: true, // Observe changes to text nodes
    attributes: true // Observe changes to attributes
};

// Function to check if elements are loaded in the DOM and populate variables with them 
function loader(interval = 500) {
    const check = setInterval(() => {
        postcode = $('input[name*="Address94394335"]')[0];
        button = $('button[id*="Address94394335"]')[0];
        multiSelect = document.querySelector('[data-field-name*="CheckboxMultiple75509060"] .lfr-ddm-checkbox-multiple');
        if (postcode && button && multiSelect) {
            clearInterval(check);
            postcodeEnter();
            observer.observe(multiSelect, observerConfig);
        }
    }, interval);
}
loader();

// Function to allow the Enter and Return key to search for postcode
function postcodeEnter() {
    postcode.addEventListener("keydown", function (event) {
        if (event.key === "Enter" || event.key === "Return") {
            event.preventDefault();
            button.click();
        }
    });
}
// Observer to look for changes in the multiselect list because of selecting an address
const callback = function (mutationsList, observer) {
    updateApiReturnArray();
    //updateMailto();
    const postcodeVal = document.querySelector(".postcode-label").textContent;
    gtag("event", "binDateView", {
        app_name: "binCollectionLookup",
        postcode: postcodeVal
    });
};

const observer = new MutationObserver(callback);

function updateApiReturnArray() {
    apiReturnArray = [];
    const allCollections = multiSelect.querySelectorAll("label");
    allCollections.forEach((collection) => {
        apiReturnArray.push({
            collectionDetails: collection.textContent
        });
    });
    //Once the data from the return is in the apiReturnArray the formatCollectionList function is launched.
    formatCollectionList(apiReturnArray);
}

// Function to create a new array of collections organised by type

function formatCollectionList(apiReturnArray) {
    // Clear the formattedArray
    formattedArray = [];

    const tempCollection = {};

    apiReturnArray.forEach((item) => {
        // Extract the collectionDetails string
        const details = item.collectionDetails;

        // Remove the curly braces and split the string into key-value pairs
        const keyValuePairs = details.replace(/[{}]/g, "").split(", ");

        // Create an object to hold the parsed data
        const parsedObject = {};

        // Iterate over the key-value pairs and add them to the object
        keyValuePairs.forEach((pair) => {
            const [key, value] = pair.split("=");
            parsedObject[key.trim()] = value.trim();
        });

        // Get the name, collection date, frequency, and day of the week
        const name = parsedObject.name;
        const collectionDate = formatDate(parsedObject.collectionDate);
        const frequency = parsedObject.frequency.includes("fornightly") ? parsedObject.frequency.replace("fornightly", "fortnightly") : parsedObject.frequency;
        const dayOfWeek = getDayName(parseInt(parsedObject.dayOfWeek));


        // Initialize the entry if it doesn't exist
        if (!tempCollection[name]) {
            tempCollection[name] = {
                name: name,
                frequency: frequency,
                dayOfWeek: dayOfWeek,
                collectionDates: []
            };
        }

        // Add the collection date to the array
        tempCollection[name].collectionDates.push(collectionDate);
    });

    // Convert the organized data object to an array and assign it to formattedArray
    formattedArray = Object.values(tempCollection);

    if (formattedArray[0].name) {
        createCardLayout();
    } else {
        clearCards();
    }
}

// Supporting functions for creating formatted array of collection dates
// Function to convert day number to day name
function getDayName(dayNumber) {
    const days = ["Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday", "Sunday"];
    return days[dayNumber - 1];
}

// Function to format date strings into the original format (e.g., "Wed 19 Feb 2025")
function formatDate(dateString) {
    const [day, dayNum, month, year] = dateString.split(" ");
    return `${day} ${dayNum} ${month} ${year}`;
}

// Create Cards //////////////////////////////////////

// Function to create and populate the cards
function populateCards() {
    const noCollection = document.querySelector('.noCollection');
    if (noCollection) {
        noCollection.remove();
    }
    const container = document.getElementById("collection-cards");
    container.innerHTML = ""; // Clear existing content

    const today = new Date().toDateString();

    formattedArray.forEach((collection) => {
        const card = document.createElement("div");
        card.className = "card";

        const title = document.createElement("h3");
        title.innerHTML = formatTitle(collection.name);
        card.appendChild(title);

        const frequency = document.createElement("p");
        frequency.innerHTML = `<strong>Frequency:</strong><br>${collection.frequency}`;
        card.appendChild(frequency);

        const nextCollection = document.createElement("p");
        let nextDate = collection.collectionDates[0];
        if (new Date(nextDate).toDateString() === today) {
            nextDate = `Today - ${nextDate}`;
        }
        nextCollection.innerHTML = `<strong>Next Collection:</strong><br>${nextDate}`;
        card.appendChild(nextCollection);

        if (collection.collectionDates.length === 2) {
            const followingCollection = document.createElement("p");
            followingCollection.innerHTML = `<strong>Following Collection:</strong><br>${collection.collectionDates[1]}`;
            card.appendChild(followingCollection);
        } else if (collection.collectionDates.length === 3) {
            const followingCollection = document.createElement("p");
            followingCollection.innerHTML = `<strong>Following Collections:</strong><br>${collection.collectionDates[1]}, ${collection.collectionDates[2]}`;
            card.appendChild(followingCollection);
        }

        container.appendChild(card);
    });
}

// Function to split the title and move bracketed content to a new line
function formatTitle(title) {
    const match = title.match(/(.*?)(\s*\(.*\))/);
    if (match) {
        return `${match[1]}<br>${match[2]}`;
    }
    return title;
}

// Function to create the container and cards
function createCardLayout() {
    // Check if the collectionResultsContainer already exists
    let existingContainer = document.querySelector(".collectionResultsContainer");
    if (existingContainer) {
        existingContainer.remove();
    }

    // Create the new elements
    let container = document.createElement("div");
    container.className = "collectionResultsContainer";

    let cards = document.createElement("div");
    cards.className = "collection-cards";
    cards.id = "collection-cards";

    container.appendChild(cards);

    // Find the element with data-field-reference="postcodeField"
    const referenceElement = document.querySelector('[data-field-reference="Address94394335"]');
    // Insert the new container after the reference element
    if (referenceElement) {
        referenceElement.parentNode.insertBefore(container, referenceElement.nextSibling);
    } else {
        console.error("Reference element not found");
    }

    // Populate the cards
    populateCards();
}

function clearCards() {

    // Create a new div element with the desired structure
    const message = document.createElement('div');
    message.setAttribute('role', 'alert');
    message.classList.add('form-feedback-item', 'noCollection');
    message.innerHTML = `
    <span class="form-feedback-indicator inline-item-before" style="color: #da1414;">
      <svg class="lexicon-icon lexicon-icon-exclamation-full" role="presentation" style="fill: #da1414;">
        <use href="https://babergh.gov.uk/o/classic-theme/images/clay/icons.svg#exclamation-full"></use>
      </svg>
    </span>
    <span style="color: #da1414;">Unable to get collection details for this address.</span>
  `;

    const referenceElement = document.querySelector('[data-field-reference="Address94394335"]');
    const resultsCards = document.querySelector('.collectionResultsContainer');
    if (resultsCards) {
        resultsCards.remove();
    }
      // Insert the new message after the reference element
    if (referenceElement) {
        referenceElement.parentNode.insertBefore(message, referenceElement.nextSibling);
    } else {
        console.error("Reference element not found");
    }
}

function updateMailto() {
        const postalAddress = document.querySelector(".callout-success span").textContent;
        if (postalAddress) {
            const mailtoLink = document.getElementById('mailto-link');
            const subjectStarter = "When is my collection day? - ";
            const newSubject = subjectStarter + postalAddress;
            mailtoLink.href = "mailto:recycling@baberghmidsuffolk.gov.uk?subject=" + encodeURIComponent(newSubject) + "&body=***Please%20include%20your%20full%20address%20and%20postcode***";
        } else {
            const mailtoLink = document.getElementById('mailto-link');
            mailtoLink.href = "mailto:recycling@baberghmidsuffolk.gov.uk?subject=When%20is%20my%20collection%20day&body=***Please%20include%20your%20full%20address%20and%20postcode***";
        }
}

const targetInput = document.querySelector('input[id*="Text06802196"]');
function handleInputChange() {
    console.log('Input value changed to:', targetInput.value);
    updateMailto();
}

const uprnObserver = new MutationObserver((mutationsList) => {
    for (let mutation of mutationsList) {
        if (mutation.type === 'attributes' && mutation.attributeName === 'value') {
            handleInputChange();
        }
    }
});
const uprnObserverConfig = { attributes: true, attributeFilter: ['value'] };
uprnObserver.observe(targetInput, uprnObserverConfig); 
 }
