// Function to create and populate the cards
function populateCards() {
    const noCollection = document.querySelector('.noCollection');
    if (noCollection) {
        noCollection.remove();
    }
    const container = document.getElementById("collection-cards");
    container.innerHTML = ""; // Clear existing content

    const today = new Date().toDateString();

    formattedArray.forEach((collection) => {
        const card = document.createElement("div");
        card.className = "card";

        const title = document.createElement("h3");
        title.innerHTML = formatTitle(collection.name);
        card.appendChild(title);

        const frequency = document.createElement("p");
        frequency.innerHTML = `<strong>Frequency:</strong><br>${collection.frequency}`;
        card.appendChild(frequency);

        const nextCollection = document.createElement("p");
        let nextDate = collection.collectionDates[0];
        if (new Date(nextDate).toDateString() === today) {
            nextDate = `Today - ${nextDate}`;
        }
        nextCollection.innerHTML = `<strong>Next Collection:</strong><br>${nextDate}`;
        card.appendChild(nextCollection);

        if (collection.collectionDates.length === 2) {
            const followingCollection = document.createElement("p");
            followingCollection.innerHTML = `<strong>Following Collection:</strong><br>${collection.collectionDates[1]}`;
            card.appendChild(followingCollection);
        } else if (collection.collectionDates.length === 3) {
            const followingCollection = document.createElement("p");
            followingCollection.innerHTML = `<strong>Following Collections:</strong><br>${collection.collectionDates[1]}, ${collection.collectionDates[2]}`;
            card.appendChild(followingCollection);
        }

        container.appendChild(card);
    });
}

// Function to split the title and move bracketed content to a new line
function formatTitle(title) {
    const match = title.match(/(.*?)(\s*\(.*\))/);
    if (match) {
        return `${match[1]}<br>${match[2]}`;
    }
    return title;
}

// Function to create the container and cards
function createCardLayout() {
    // Check if the collectionResultsContainer already exists
    let existingContainer = document.querySelector(".collectionResultsContainer");
    if (existingContainer) {
        existingContainer.remove();
    }

    // Create the new elements
    let container = document.createElement("div");
    container.className = "collectionResultsContainer";

    let cards = document.createElement("div");
    cards.className = "collection-cards";
    cards.id = "collection-cards";

    container.appendChild(cards);

    // Find the element with data-field-reference="postcodeField"
    const referenceElement = document.querySelector('[data-field-reference="Address94394335"]');
    // Insert the new container after the reference element
    if (referenceElement) {
        referenceElement.parentNode.insertBefore(container, referenceElement.nextSibling);
    } else {
        console.error("Reference element not found");
    }

    // Populate the cards
    populateCards();
}

